const listTerminalizableRunningOrchestrationRuns = `-- name: ListTerminalizableRunningOrchestrationRuns :many
SELECT r.id, r.tenant_id, r.owner_subject, r.lifecycle_status, r.planning_status, r.status_version, r.planner_epoch, r.last_event_seq, r.root_task_id, r.goal, r.input, r.requested_control_policy, r.control_policy, r.source_metadata, r.policies, r.created_by, r.terminal_reason, r.created_at, r.updated_at, r.finished_at
FROM orchestration_runs r
WHERE r.lifecycle_status = 'running'
  AND NOT EXISTS (
    SELECT 1
    FROM orchestration_planning_intents i
    WHERE i.run_id = r.id
      AND i.status IN ('pending', 'processing', 'failed')
  )
  AND NOT EXISTS (
    SELECT 1
    FROM orchestration_task_attempts a
    WHERE a.run_id = r.id
      AND a.status IN ('created', 'claimed', 'binding', 'running')
  )
  AND NOT EXISTS (
    SELECT 1
    FROM orchestration_human_checkpoints c
    WHERE c.run_id = r.id
      AND c.status = 'open'
  )
  AND NOT EXISTS (
    -- excludes runs with any non-terminal task OR any failed task (failed is
    -- absent from the IN list, so a failed task triggers this NOT EXISTS).
    SELECT 1
    FROM orchestration_tasks t
    WHERE t.run_id = r.id
      AND t.superseded_by_planner_epoch IS NULL
      AND t.status NOT IN ('completed', 'cancelled')
  )
  AND EXISTS (
    SELECT 1
    FROM orchestration_tasks t
    WHERE t.run_id = r.id
      AND t.superseded_by_planner_epoch IS NULL
      AND t.role = 'final'
      AND t.status = 'completed'
  )
ORDER BY r.updated_at ASC, r.id ASC
LIMIT ?1
`

